import{_ as t,o as a,c as o,a3 as s}from"./chunks/framework.DACwFHq9.js";const g=JSON.parse('{"title":"Using AI Features","description":"Learn how to invoke AI chat, use the AI rewrite palette, and explore semantic search.","frontmatter":{"title":"Using AI Features","description":"Learn how to invoke AI chat, use the AI rewrite palette, and explore semantic search.","keywords":"AI chat, AI palette, rewrite, summarize, translate, semantic search, diagnostic trace, references","category":"AI"},"headers":[],"relativePath":"ai/features.md","filePath":"ai/features.md","lastUpdated":1784869909000}'),r={name:"ai/features.md"};function n(i,e,l,c,h,d){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="ai-features" tabindex="-1">AI Features <a class="header-anchor" href="#ai-features" aria-label="Permalink to &quot;AI Features&quot;">​</a></h1><p>AI capabilities in Notely are integrated across your editor workspace, left panel dashboards, and settings.</p><hr><h2 id="_1-global-note-scoped-chat-panel" tabindex="-1">1. Global &amp; Note-Scoped Chat Panel <a class="header-anchor" href="#_1-global-note-scoped-chat-panel" aria-label="Permalink to &quot;1. Global &amp; Note-Scoped Chat Panel&quot;">​</a></h2><p>You can chat with Notely&#39;s assistant in two ways:</p><ul><li><strong>Note-Scoped</strong>: While editing a note, toggle the assistant from the right side edge or the toolbar to brainstorm inside the active document.</li><li><strong>Global Chat</strong>: While on the landing page (with no note open), click the <strong>Sparkles</strong> icon under the <strong>Quick Actions</strong> toolbar on the left panel rail. This opens the AI sidebar to chat about the entire workspace.</li></ul><h3 id="context-scope-options" tabindex="-1">Context Scope Options <a class="header-anchor" href="#context-scope-options" aria-label="Permalink to &quot;Context Scope Options&quot;">​</a></h3><p>Inside the chat panel, you can choose what context to send with your message:</p><ol><li><strong>Auto</strong>: Selects highlighted text if active, otherwise the current note.</li><li><strong>Selection</strong>: Restricts context to active text selection.</li><li><strong>Block</strong>: Restricts context to active cursor paragraph.</li><li><strong>Note</strong>: Sends the entire note.</li><li><strong>Workspace</strong>: Extends context by searching relevant chunks across the whole note library.</li></ol><h3 id="sourced-references" tabindex="-1">Sourced References <a class="header-anchor" href="#sourced-references" aria-label="Permalink to &quot;Sourced References&quot;">​</a></h3><p>Whenever the assistant retrieves documents to answer your question, a <strong>Referred Notes</strong> chip list is rendered under the assistant message bubble. Hover over these chips to see file paths and relevance match percentages.</p><hr><h2 id="_2-ai-palette-actions" tabindex="-1">2. AI Palette Actions <a class="header-anchor" href="#_2-ai-palette-actions" aria-label="Permalink to &quot;2. AI Palette Actions&quot;">​</a></h2><p>Refactor or rewrite text inside the editor:</p><ol><li>Highlight target text selection in the Markdown editor.</li><li>Press <strong><code>Ctrl + Space</code></strong> or right-click and select <strong>AI Actions</strong>.</li><li>Choose an action from the palette (e.g. Summarize, Change Tone, Improve Readability).</li></ol><hr><h2 id="_3-persona-customization-preset-avatars" tabindex="-1">3. Persona Customization &amp; Preset Avatars <a class="header-anchor" href="#_3-persona-customization-preset-avatars" aria-label="Permalink to &quot;3. Persona Customization &amp; Preset Avatars&quot;">​</a></h2><p>Customize how the AI talks to you:</p><ul><li>Open <strong>AI Settings</strong> and click <strong>Manage Personas</strong>.</li><li>Select or create custom personas, and change their system prompt instructions.</li><li>Select a preset emoji avatar (🤖, 💻, 🧠, etc.) next to the custom avatar field to represent them in the chat panel.</li></ul><hr><h2 id="_4-diagnostics-tool-trace-log" tabindex="-1">4. Diagnostics &amp; Tool Trace Log <a class="header-anchor" href="#_4-diagnostics-tool-trace-log" aria-label="Permalink to &quot;4. Diagnostics &amp; Tool Trace Log&quot;">​</a></h2><p>If you want to inspect how the AI retrieves data or what tools it invokes:</p><ol><li>Go to <strong>AI Diagnostics</strong> / <strong>AI Health</strong> page.</li><li>Select a conversation session from the list.</li><li>Click to expand the collapsible <strong>Tool calls</strong> inspector under the assistant bubbles. This details the exact tool name (e.g. <code>read_note</code>, <code>search_notes</code>), arguments passed, and raw return values.</li></ol>',23)])])}const u=t(r,[["render",n]]);export{g as __pageData,u as default};
